def run_command(cmd, description, cwd=None, env=None):
    """Run a shell command and handle errors."""
    logger.info(f"Starting: {description}")
    logger.info(f"Command: {' '.join(cmd) if isinstance(cmd, list) else cmd}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            cmd,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout:
            for line in result.stdout.strip().split("\n"):
                logger.info(f"  {line}")

        if result.returncode != 0:
            logger.error(f"Failed: {description}")
            if result.stderr:
                for line in result.stderr.strip().split("\n"):
                    logger.error(f"  {line}")
            return False

        logger.info(f"Completed: {description}")
        return True

    except subprocess.TimeoutExpired:
        logger.error(f"Timeout: {description} exceeded 300s limit")
        return False
    except FileNotFoundError:
        logger.error(f"Command not found: {cmd[0] if isinstance(cmd, list) else cmd}")
        return False


def check_prerequisites():
    """Verify that required files and tools exist."""
    logger.info("=" * 60)
    logger.info("STEP 1: Checking prerequisites")
    logger.info("=" * 60)

    errors = []

    # Check Python version
    python_version = sys.version_info
    logger.info(f"Python version: {python_version.major}.{python_version.minor}.{python_version.micro}")
    if python_version < (3, 8):
        errors.append("Python 3.8+ is required")

    # Check requirements.txt exists
    if not REQUIREMENTS_FILE.exists():
        errors.append(f"Requirements file not found: {REQUIREMENTS_FILE}")
    else:
        logger.info(f"Found requirements file: {REQUIREMENTS_FILE}")

    # Check source directory exists
    if not SRC_DIR.exists():
        logger.warning(f"Source directory not found: {SRC_DIR} (will look for .py files in project root)")

    # Check test directory exists
    if not TEST_DIR.exists():
        logger.warning(f"Test directory not found: {TEST_DIR} (will attempt to discover tests)")

    # Check pip is available
    if not shutil.which("pip") and not shutil.which("pip3"):
        errors.append("pip is not installed or not in PATH")

    if errors:
        for error in errors:
            logger.error(f"Prerequisite check failed: {error}")
        return False

    logger.info("All prerequisites satisfied")
    return True


def clean_build_artifacts():
    """Remove previous build and dist directories."""
    logger.info("Cleaning previous build artifacts...")

    for directory in [BUILD_DIR, DIST_DIR]:
        if directory.exists():
            shutil.rmtree(directory)
            logger.info(f"Removed: {directory}")

    # Clean __pycache__ directories
    for pycache in PROJECT_ROOT.rglob("__pycache__"):
        shutil.rmtree(pycache)

    # Clean .pyc files
    for pyc_file in PROJECT_ROOT.rglob("*.pyc"):
        pyc_file.unlink()

    logger.info("Build artifacts cleaned")
    return True


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    logger.info("=" * 60)
    logger.info("STEP 2: Installing dependencies")
    logger.info("=" * 60)

    pip_cmd = [sys.executable, "-m", "pip"]

    # Upgrade pip first
    success = run_command(
        pip_cmd + ["install", "--upgrade", "pip"],
        "Upgrading pip",
    )
    if not success:
        logger.warning("pip upgrade failed, continuing with current version")

    # Install dependencies from requirements.txt
    success = run_command(
        pip_cmd + [
            "install",
            "-r", str(REQUIREMENTS_FILE),
            "--no-cache-dir",
            "--quiet",
        ],
        "Installing project dependencies",
    )
    if not success:
        logger.error("Dependency installation failed")
        return False

    # Install test dependencies if they exist
    test_requirements = PROJECT_ROOT / "requirements-test.txt"
    if test_requirements.exists():
        success = run_command(
            pip_cmd + [
                "install",
                "-r", str(test_requirements),
                "--no-cache-dir",
                "--quiet",
            ],
            "Installing test dependencies",
        )
        if not success:
            logger.error("Test dependency installation failed")
            return False

    # Ensure pytest is available for running tests
    success = run_command(
        pip_cmd + ["install", "pytest", "pytest-cov", "--quiet", "--no-cache-dir"],
        "Ensuring test runner is installed",
    )
    if not success:
        logger.warning("Could not install pytest, tests may fail")

    # Verify installed packages
    run_command(
        pip_cmd + ["list", "--format=columns"],
        "Listing installed packages",
    )

    logger.info("Dependencies installed successfully")
    return True


